import{_ as o,o as t,c as s,a2 as n}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"RFC 0016 — Web Push notifications","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0016-web-push.md","filePath":"rfcs/0016-web-push.md"}'),i={name:"rfcs/0016-web-push.md"};function r(a,e,d,c,l,h){return t(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="rfc-0016-—-web-push-notifications" tabindex="-1">RFC 0016 — Web Push notifications <a class="header-anchor" href="#rfc-0016-—-web-push-notifications" aria-label="Permalink to &quot;RFC 0016 — Web Push notifications&quot;">​</a></h1><p><strong>Status:</strong> Accepted<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>runtime/next.config.ts</code> + a new <code>runtime/worker/</code> (service-worker push handler), platform DB (<code>packages/db</code> — a new <code>push_subscriptions</code> table + helpers), runtime API routes + the <code>web-push</code> dependency, <code>runtime/public/manifest.json</code>, <code>.env.example</code> + <code>docs/self-hosting.md</code> (VAPID keys), Account (enable-push toggle), Console (broadcast push), SRS; <strong>builds on RFC 0015</strong> (Notification Center) and RFC 0001 / PLT-09 (PWA)<br><strong>Incorporated into plan:</strong> Yes — scheduled as roadmap Task 0.7.1; documentation-first. This RFC specifies the Web Push delivery channel and the end-to-end flows; SRS requirement IDs (proposed <code>NOTIF-*</code> / <code>PUSH-*</code>), scheduling, and task allocation are deferred.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Add <strong>Web Push</strong> so a user receives notifications even when the Sovereign tab is closed or backgrounded — the natural completion of the PWA story (PLT-09). Push is a <strong>delivery channel</strong>, not a new notification concept: it transports the same inbox notifications defined in <strong>RFC 0015</strong>. The pieces are standard and the codebase is ready for all of them:</p><ul><li><strong>VAPID keys</strong> as optional, no-default env secrets (push is disabled when unset);</li><li>a <strong>service-worker</strong> <code>push</code> + <code>notificationclick</code> handler injected via <code>@ducanh2912/next-pwa</code>&#39;s <code>customWorkerSrc</code>;</li><li>a <strong><code>push_subscriptions</code></strong> table (one row per device/endpoint);</li><li>a <strong>browser permission + subscription flow</strong> in Account;</li><li><strong>server-side send</strong> via the <code>web-push</code> library on the RFC 0015 fan-out.</li></ul><p><strong>Plugins never touch push.</strong> They call <code>sdk.notifications.send</code> (RFC 0015); the platform decides whether a given recipient also gets a push. This keeps transport, secrets, and abuse limits entirely platform-controlled.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>RFC 0015 delivers notifications <strong>in-app</strong> (badge + toast) — but only while a tab is open. The whole point of an installable PWA (PLT-09) is that it behaves like an app, and apps notify you when they&#39;re closed. Without push, a self-hosted user must keep a tab open to learn that a long job finished or an admin posted downtime. Push closes that gap using web standards, with <strong>no external service</strong> and <strong>no telemetry</strong> — consistent with Sovereign&#39;s positioning.</p><h2 id="relationship-to-rfc-0015" tabindex="-1">Relationship to RFC 0015 <a class="header-anchor" href="#relationship-to-rfc-0015" aria-label="Permalink to &quot;Relationship to RFC 0015&quot;">​</a></h2><p>RFC 0015 is the <strong>source of truth</strong> (the inbox) and the <strong>send API</strong> plugins use. This RFC adds <strong>one more branch</strong> to RFC 0015&#39;s platform-owned fan-out: after writing the inbox row (and a toast if active), the platform also pushes to the recipient&#39;s subscribed devices when the category isn&#39;t muted. No new SDK surface, no new plugin permission — push is a platform capability.</p><h2 id="current-state-feasibility-verified" tabindex="-1">Current state / feasibility (verified) <a class="header-anchor" href="#current-state-feasibility-verified" aria-label="Permalink to &quot;Current state / feasibility (verified)&quot;">​</a></h2><ul><li><strong>Custom SW injection exists.</strong> <code>@ducanh2912/next-pwa@10.2.9</code> supports <strong><code>customWorkerSrc</code></strong> (default dir <code>worker/</code>), which compiles custom service-worker code into the generated <code>sw.js</code> at build — so a hand-written push handler <strong>survives Workbox regeneration</strong>. Today <code>runtime/next.config.ts</code> sets <code>dest</code>/<code>disable</code>/<code>register</code>/<code>reloadOnOnline</code>/<code>fallbacks</code> but <strong>no</strong> custom worker; this RFC adds one. (SW stays disabled in dev, so push is a production-build concern — like installability.)</li><li><strong>CSP already allows it.</strong> <code>runtime/src/security.ts</code> emits <code>worker-src &#39;self&#39;</code>; the same-origin SW registration passes. WebAuthn-style API (<code>PushManager</code>, <code>Notification</code>) isn&#39;t governed by <code>connect-src</code>. No CSP change needed.</li><li><strong>No <code>web-push</code> dependency yet.</strong> It is pure-Node (no native bindings), so it is traced into the standalone output with <strong>zero Dockerfile changes</strong> (just a new entry in <code>runtime/package.json</code>).</li><li><strong>Secret pattern established.</strong> <code>apps/auth/src/env.ts</code> validates required secrets with no defaults (<code>AUTH_SECRET</code>, <code>SOVEREIGN_ADMIN_KEY</code>); VAPID keys follow the same discipline (as <strong>optional</strong> — see below).</li><li><strong>Table + parity pattern.</strong> New platform tables follow <code>packages/db</code>&#39;s schema/sqlite + schema/postgres + bootstrap DDL, guarded by the schema-parity test; new env vars are enforced by the docs-parity / env-parity tests.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="vapid-keys-optional-no-default-secrets" tabindex="-1">VAPID keys (optional, no-default secrets) <a class="header-anchor" href="#vapid-keys-optional-no-default-secrets" aria-label="Permalink to &quot;VAPID keys (optional, no-default secrets)&quot;">​</a></h3><p>Two env vars — <strong><code>VAPID_PUBLIC_KEY</code></strong> and <strong><code>VAPID_PRIVATE_KEY</code></strong> (generated via <code>npx web-push generate-vapid-keys</code>). They are <strong>optional</strong>: when <strong>unset, Web Push is disabled</strong> (the Account toggle hides itself, the platform fan-out skips the push branch). This honours &quot;no secrets with defaults&quot; — there is no fallback key — while keeping push <strong>opt-in</strong> for self-hosters who don&#39;t want it. Validation is <strong>both-or-neither</strong>: if exactly one is set, the runtime fails loudly at startup. The public key is sent to the client for subscription; the private key signs sends server-side and never leaves the server.</p><h3 id="service-worker-push-notificationclick" tabindex="-1">Service worker (<code>push</code> + <code>notificationclick</code>) <a class="header-anchor" href="#service-worker-push-notificationclick" aria-label="Permalink to &quot;Service worker (`push` + `notificationclick`)&quot;">​</a></h3><p>A committed <code>runtime/worker/*.ts</code> provides:</p><ul><li>a <strong><code>push</code></strong> handler — parse the payload (title/body/url/icon from the RFC 0015 notification) and <code>showNotification</code>;</li><li>a <strong><code>notificationclick</code></strong> handler — focus an existing client or open the notification&#39;s <code>url</code>.</li></ul><p>It is wired via <code>customWorkerSrc</code> in <code>runtime/next.config.ts</code>. This is the <strong>one place</strong> custom SW code lives; it is compiled into <code>sw.js</code> each build and therefore is <em>not</em> part of the gitignored generated bundle — the source file is committed, the compiled output is not.</p><h3 id="subscription-store" tabindex="-1">Subscription store <a class="header-anchor" href="#subscription-store" aria-label="Permalink to &quot;Subscription store&quot;">​</a></h3><p>A <code>push_subscriptions</code> table (dialect schema + bootstrap + parity pattern): <code>id</code>, <code>user_id</code>, <code>tenant_id</code>, <code>endpoint</code> (unique), <code>p256dh</code>, <code>auth</code>, <code>created_at</code>, <code>updated_at</code>. <code>packages/db</code> helpers: save/upsert by endpoint, list-by-user, delete. A send that returns <strong><code>410 Gone</code></strong> (or <code>404</code>) prunes the dead subscription.</p><h3 id="client-flow-account" tabindex="-1">Client flow (Account) <a class="header-anchor" href="#client-flow-account" aria-label="Permalink to &quot;Client flow (Account)&quot;">​</a></h3><p>Account gains an <strong>&quot;Enable notifications on this device&quot;</strong> control:</p><ol><li>request <code>Notification</code> permission;</li><li><code>navigator.serviceWorker.ready</code> → <code>PushManager.subscribe({ userVisibleOnly: true, applicationServerKey: &lt;VAPID public key&gt; })</code>;</li><li><code>POST /api/account/push/subscribe</code> with the subscription JSON → stored.</li></ol><p>An unsubscribe path removes the local subscription and deletes the stored row. <strong>iOS Safari constraint (stated plainly):</strong> Web Push is delivered only to an <strong>installed</strong> PWA (Add to Home Screen) on iOS 16.4+, not to the browser tab — the UI should explain this so iOS users install first.</p><h3 id="server-side-send" tabindex="-1">Server-side send <a class="header-anchor" href="#server-side-send" aria-label="Permalink to &quot;Server-side send&quot;">​</a></h3><p>On the RFC 0015 fan-out, after the inbox row is written, the platform looks up the recipient&#39;s <code>push_subscriptions</code> and sends each via <strong><code>web-push</code></strong>, signed with the VAPID private key, <strong>subject to the user&#39;s category mute prefs</strong>. <strong>Admin broadcasts</strong> (RFC 0015) fan out to push under the <strong>same four guardrails</strong> — audited to the activity log, rate-limited, audience-scoped, user-opt-out respected (except the reserved critical-security class).</p><h3 id="configuration-docker" tabindex="-1">Configuration &amp; Docker <a class="header-anchor" href="#configuration-docker" aria-label="Permalink to &quot;Configuration &amp; Docker&quot;">​</a></h3><ul><li>Add <strong><code>web-push</code></strong> to <code>runtime/package.json</code> (pure-Node; standalone trace handles the rest — no Dockerfile change).</li><li>Add <code>VAPID_PUBLIC_KEY</code> / <code>VAPID_PRIVATE_KEY</code> to <strong>both</strong> compose files and <code>.env.example</code>, and document them in <code>docs/self-hosting.md</code> (the env-parity test enforces this).</li><li>Optionally add a <code>badges</code> icon to <code>runtime/public/manifest.json</code> for nicer notification badging.</li></ul><h2 id="ui-flows" tabindex="-1">UI flows <a class="header-anchor" href="#ui-flows" aria-label="Permalink to &quot;UI flows&quot;">​</a></h2><p><strong>Enable push</strong> — Account → &quot;Enable notifications on this device&quot; → browser permission prompt → subscribed; the device now receives background notifications. (On iOS, the control explains the app must be installed first.)</p><p><strong>Background delivery</strong> — a plugin (or admin broadcast) creates a notification while the user&#39;s app is closed → the platform sends Web Push to the user&#39;s subscribed devices → the OS shows it → tapping it opens the notification&#39;s <code>url</code> in Sovereign.</p><p><strong>Disable / cleanup</strong> — the user toggles push off (subscription removed); a stale endpoint that returns <code>410</code> is pruned automatically on the next send.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Legacy GCM (<code>gcm_sender_id</code> in the manifest).</strong> Rejected — VAPID is the modern, provider-agnostic Web Push standard supported across current browsers; no Google project required.</li><li><strong>A third-party push service (OneSignal, Firebase, etc.).</strong> Rejected — an external dependency that sees user notifications, contrary to self-host + no-telemetry. VAPID + <code>web-push</code> keeps everything on the instance.</li><li><strong>A plugin-level push permission / direct plugin push.</strong> Rejected — push is platform-managed; plugins only write to the inbox (RFC 0015) and the platform decides delivery. No new permission is introduced.</li><li><strong>Required VAPID keys.</strong> Rejected — push is opt-in; optional-with-both-or-neither keeps &quot;no secrets with defaults&quot; without forcing every self-hoster to configure push.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>VAPID key rotation</strong> — procedure and what happens to existing subscriptions when keys rotate (re-subscribe flow).</li><li><strong>Per-category push prefs</strong> — granularity beyond the RFC 0015 mute (e.g. push for <code>security</code> only, in-app for the rest).</li><li><strong>App icon badge</strong> — use <code>navigator.setAppBadge</code> for an unread count on the installed icon?</li><li><strong>Notification grouping/collapsing</strong> — tag/replace strategy to avoid flooding the OS tray.</li><li><strong>Requirement IDs</strong> — proposed <code>NOTIF-*</code> / <code>PUSH-*</code> entries, deferred until accepted.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>Documentation-first (this RFC).</strong> Design + flows captured; no code, no SRS edits, no scheduling.</li><li><strong>When accepted &amp; scheduled (after RFC 0015):</strong> the <code>customWorkerSrc</code> push handler, the <code>push_subscriptions</code> table + helpers, the Account subscribe/unsubscribe flow + API routes, the <code>web-push</code> send on the RFC 0015 fan-out (incl. admin broadcasts), VAPID env wiring + docs, and the manifest badge.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; Web Push as a background delivery channel for RFC 0015 inbox notifications — VAPID optional secrets, <code>customWorkerSrc</code> SW handler, <code>push_subscriptions</code> store, Account opt-in, platform-owned send; documentation-first.</td></tr><tr><td>0.2</td><td>Jun 2026</td><td>Accepted; scheduled in the roadmap as Task 0.7.1.</td></tr></tbody></table>',42)])])}const g=o(i,[["render",r]]);export{p as __pageData,g as default};
